import json
from lfx.custom import Component
from lfx.inputs.inputs import MessageTextInput
from lfx.io import Output
from lfx.schema.data import Data


class ToolCallingAgentComponent_0001(Component):
    """Synthetic data capability for Test Management System. Returns realistic generated sample data
    instead of calling a real API, so the agent can be tested end-to-end before the real
    system is connected. Swap to a real connector later by providing the API details."""

    display_name = "Test Case Storage"
    description = "Returns synthetic/test data for Test Management System (no real API call). Provide 'payload' with the request fields."
    icon = "TestTube"
    name = "ToolCallingAgentComponent_0001"

    inputs = [
        MessageTextInput(name="payload", display_name="Request Payload",
                         info="The request fields (JSON). Echoed back in the synthetic response.",
                         value="{}", required=False, tool_mode=True),
        MessageTextInput(name="sample_response", display_name="Sample Response (JSON)",
                         info="The synthetic response template returned to the agent.",
                         value="{\"id\": \"TC-2024-001\", \"title\": \"User Login with Valid Credentials\", \"description\": \"Verify that a user can successfully log in with valid email and password\", \"preconditions\": \"User is on the login page; User has a valid account\", \"steps\": [\"Enter valid email address\", \"Enter valid password\", \"Click Login button\"], \"expected_result\": \"User is logged in and redirected to dashboard\", \"priority\": \"high\", \"module\": \"Authentication\", \"tags\": [\"smoke\", \"critical\"], \"created_at\": \"2024-01-15T10:30:00Z\", \"status\": \"active\"}", required=False),
    ]

    outputs = [
        Output(name="result", display_name="Result", method="call_api", tool_mode=True),
    ]

    def call_api(self) -> Data:
        try:
            try:
                sent = json.loads(getattr(self, "payload", "") or "{}")
            except Exception:
                sent = {}
            try:
                sample = json.loads(getattr(self, "sample_response", "") or "{}")
            except Exception:
                sample = {}
            # Merge submitted fields into the sample so the response reflects the input.
            if isinstance(sample, dict):
                merged = dict(sample)
                if isinstance(sent, dict):
                    for k, v in sent.items():
                        merged.setdefault(k, v)
                result = {"capability": "Test Case Storage", "status": "completed",
                          "synthetic": True, "result": merged}
            else:
                result = {"capability": "Test Case Storage", "status": "completed",
                          "synthetic": True, "result": sample}
        except Exception as e:
            result = {"capability": "Test Case Storage", "status": "error", "synthetic": True, "error": str(e)}
        self.status = result
        return Data(data=result)
